// Lista de tag IDs que deseja remover
const tagIdsToRemove = $('Tags para remoção').first().json.tagIds;

// Lista de associações de tags obtidas do passo anterior
const contactTags = $input.first().json.contactTags;

// Filtra associações correspondentes aos tagIds fornecidos
const filteredTags = contactTags
  .filter(contactTag => tagIdsToRemove.includes(contactTag.tag))
  .map(contactTag => ({ contactTagId: contactTag.id }));

// Retorna o resultado, incluindo uma flag indicando se encontrou algo
return filteredTags.length > 0
  ? filteredTags
  : [{ noTagsFound: true }];

const inputDate = $input.first().json['DATA RMD']; // Exemplo: "06/01/2025" (segunda-feira)

// Função para converter string "DD/MM/YYYY" para um objeto Date
function parseDate(dateStr) {
    const [day, month, year] = dateStr.split("/").map(Number);
    return new Date(year, month - 1, day); // JavaScript usa mês indexado em 0
}

// Função para adicionar dias e formatar como "DD/MM/YYYY"
function addDays(date, days) {
    const newDate = new Date(date);
    newDate.setDate(newDate.getDate() + days);
    return `${newDate.getDate().toString().padStart(2, '0')}/${(newDate.getMonth() + 1).toString().padStart(2, '0')}/${newDate.getFullYear()}`;
}

// Converte a data inicial (segunda-feira)
const monday = parseDate(inputDate);

// Calcula os dias seguintes
const tuesday = addDays(monday, 2);
const wednesday = addDays(monday, 3);
const thursday = addDays(monday, 4);
const friday = addDays(monday, 5);

// Retorna a saída formatada corretamente
return [
  {
    "segunda-feira": `${inputDate}`,
    "terça-feira": `${tuesday}`,
    "quarta-feira": `${wednesday}`,
    "quinta-feira": `${thursday}`,
    "sexta-feira": `${friday}`
  }
];

const opcoes = ['2', '5', '7', '10'];
const indice = Math.floor(Math.random() * opcoes.length);
const opcaoSelecionada = opcoes[indice];

return [
  {
    json: {
      opcao: opcaoSelecionada
    }
  }
];

