// === CONFIG ===
// Troque "Webhook" pelo nome EXATO do seu nó Webhook, se for diferente.
const WEBHOOK_NODE = "Webhook";

// === HELPERS ===
function get(obj, path) {
  return path.split('.').reduce((o, k) => (o && o[k] !== undefined ? o[k] : undefined), obj);
}
function urlDecodeSafe(s){ try { return decodeURIComponent(s); } catch { return s; } }
function tryParseBase64Json(s){
  try{
    const b64 = s.replace(/-/g, '+').replace(/_/g, '/');
    const json = Buffer.from(b64, 'base64').toString('utf8');
    const obj = JSON.parse(json);
    return {
      utm_source: obj.us ?? obj.utm_source ?? '',
      utm_medium: obj.um ?? obj.utm_medium ?? '',
      utm_campaign: obj.uc ?? obj.utm_campaign ?? '',
      utm_content: obj.uct ?? obj.utm_content ?? '',
      utm_term: obj.ut ?? obj.utm_term ?? '',
    };
  } catch { return null; }
}
function splitPlain(s){
  const sep = s.includes('|') ? '|' : (s.includes('~') ? '~' : '|');
  const parts = s.split(sep).map(v => urlDecodeSafe(v.replace(/\+/g, ' ').trim()));
  while (parts.length < 5) parts.push('');
  const [utm_source, utm_medium, utm_campaign, utm_content, utm_term] = parts;
  return { utm_source, utm_medium, utm_campaign, utm_content, utm_term };
}
function parseXcod(s){
  if (!s) return { utm_source:'', utm_medium:'', utm_campaign:'', utm_content:'', utm_term:'' };
  const asJson = tryParseBase64Json(s);
  return asJson ?? splitPlain(s);
}

// === CAPTURA O xcod DIRETO DO NÓ WEBHOOK ===
// Pega os itens do nó "Webhook" (saída 0)
const webhookItems = $items(WEBHOOK_NODE, 0) || [];
const w = webhookItems[0]?.json || {};

// O payload pode vir "embrulhado" em body.data... (URL de teste) ou direto em data...
const candidates = [
  get(w, 'body.data.purchase.origin.xcod'),
  get(w, 'data.purchase.origin.xcod'),
  get(w, 'purchase.origin.xcod'),
  get(w, 'origin.xcod'),
];

const xcod = (candidates.find(v => typeof v === 'string' && v.length) || '').toString();

// Faz o parse das UTMs
const utm = parseXcod(xcod);

// === OUTPUT APENAS AS MÉTRICAS ===
return [{
  json: {
    utm_source: utm.utm_source,
    utm_medium: utm.utm_medium,
    utm_campaign: utm.utm_campaign,
    utm_content: utm.utm_content,
    utm_term: utm.utm_term,
  }
}];

